(function(){
  if (window.__ads_loader_init) return;
  window.__ads_loader_init = true;

  function loadAds(){
    if (window.__ads_loaded) return;
    window.__ads_loaded = true;

    var s = document.createElement('script');
    s.src = 'https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=ca-pub-2572770204602497';
    s.async = true;
    s.crossOrigin = 'anonymous';
    s.onload = function(){ window.dispatchEvent(new Event('adsense:ready')); };
    document.head.appendChild(s);

    var amp = document.createElement('script');
    amp.async = true;
    amp.setAttribute('custom-element','amp-auto-ads');
    amp.src = 'https://cdn.ampproject.org/v0/amp-auto-ads-0.1.js';
    document.head.appendChild(amp);

    if (document.body && !document.querySelector('amp-auto-ads')){
      var autoAds = document.createElement('amp-auto-ads');
      autoAds.setAttribute('type','adsense');
      autoAds.setAttribute('data-ad-client','ca-pub-2572770204602497');
      document.body.appendChild(autoAds);
    }
  }

  window.__ads_loadAds = loadAds;
  loadAds();
})();

(function(){
  var page = document.querySelector('._page');
  if (!page) return;
  if (page.querySelector('ins.adsbygoogle[data-ad-slot="6879550993"]')) return;
  var AD_HTML = '<ins class="adsbygoogle" style="display:block;margin:32px 0" data-ad-client="ca-pub-2572770204602497" data-ad-layout="in-article" data-ad-slot="6879550993" data-ad-format="fluid"></ins>';
  var BLOCK = 'H1,H2,H3,H4,H5,H6,PRE,CODE,TABLE,FIGURE,BLOCKQUOTE,UL,OL,DETAILS,SUMMARY';
  var MIN_CHARS = 200;
  var children = Array.from(page.children).filter(function(el){
    var tag = el.tagName;
    return tag !== 'SCRIPT' && tag !== 'STYLE' && tag !== 'INS';
  });
  var total = children.reduce(function(s,el){ return s + (el.textContent||'').trim().length; }, 0);
  if (total < MIN_CHARS*2) { return; }
  var half = total/2;
  var acc = 0;
  var insertAfter = null;
  for (var i=0;i<children.length;i++){
    var el = children[i];
    var len = (el.textContent||'').trim().length;
    var prevAcc = acc;
    acc += len;
    if (acc < total*0.3) continue;
    if (acc >= half){
      var closer = Math.abs(prevAcc-half) < Math.abs(acc-half) ? i-1 : i;
      closer = Math.max(0, Math.min(closer, children.length-2));
      var candidate = children[closer];
      if (candidate.matches(BLOCK) && closer+1 < children.length-1) closer++;
      insertAfter = children[closer];
      break;
    }
  }
  if (!insertAfter) insertAfter = children[Math.floor(children.length/2)-1];
  if (!insertAfter) return;
  var wrap = document.createElement('div');
  wrap.innerHTML = AD_HTML;
  var el = wrap.firstElementChild;
  insertAfter.insertAdjacentElement('afterend', el);
  try{ (adsbygoogle = window.adsbygoogle || []).push({}); el.dataset.adsPushed = '1'; }catch(e){}
})();

(function(){
  function pushAll(){
    var ins = document.querySelectorAll('ins.adsbygoogle:not([data-ad-status]):not([data-ads-pushed])');
    if (!ins || ins.length === 0) return;
    ins.forEach(function(el){
      try{ (adsbygoogle = window.adsbygoogle || []).push({}); el.setAttribute('data-ads-pushed','1'); }catch(e){}
    });
  }

  if (window.__ads_loaded){
    if (window.adsbygoogle && typeof window.adsbygoogle.push === 'function'){
      pushAll();
    } else {
      window.addEventListener('adsense:ready', pushAll, { once: true });
    }
  } else {
    window.addEventListener('adsense:ready', pushAll, { once: true });
  }
})();

(function(){
  if (window.__ads_lazy_init) return;
  window.__ads_lazy_init = true;

  function trigger(){
    if (window.__ads_lazy) return;
    window.__ads_lazy = true;
    var ins = document.querySelectorAll('ins.adsbygoogle:not([data-ad-status]):not([data-ads-pushed])');
    if (!ins || ins.length === 0) return;
    var pushFn = function(){
      ins.forEach(function(el){
        try{ (adsbygoogle = window.adsbygoogle || []).push({}); el.setAttribute('data-ads-pushed','1'); }catch(e){}
      });
    };
    if (window.__ads_loaded && window.adsbygoogle && typeof window.adsbygoogle.push === 'function'){
      pushFn();
    } else {
      window.addEventListener('adsense:ready', pushFn, { once: true });
    }
  }

  window.addEventListener('scroll', trigger, { once: true });
})();
